function toDownloadableModel(model) {
	const { name, url, directory } = model.representative;
	if (!url || !directory) return null;
	const downloadableModel = {
		name,
		url,
		directory
	};
	return isModelDownloadable(downloadableModel) ? downloadableModel : null;
}
