//#region src/stores/helpCenterStore.ts
var useHelpCenterStore = defineStore("helpCenter", () => {
	const isVisible = ref(false);
	const toggle = () => {
		isVisible.value = !isVisible.value;
	};
	const show = () => {
		isVisible.value = true;
	};
	const hide = () => {
		isVisible.value = false;
	};
	return {
		isVisible,
		toggle,
		show,
		hide
	};
});
