//#region src/composables/useHelpCenter.ts
function useHelpCenter() {
	const settingStore = useSettingStore();
	const releaseStore = useReleaseStore();
	const helpCenterStore = useHelpCenterStore();
	const { isVisible: isHelpCenterVisible } = storeToRefs(helpCenterStore);
	const { shouldShowRedDot: showReleaseRedDot } = storeToRefs(releaseStore);
	const conflictDetection = useConflictDetection();
	const { show: showNodeConflictDialog } = useNodeConflictDialog();
	const { shouldShowRedDot: shouldShowConflictRedDot, markConflictsAsSeen } = useConflictAcknowledgment();
	const shouldShowRedDot = computed(() => {
		return showReleaseRedDot.value || shouldShowConflictRedDot.value;
	});
	const sidebarLocation = computed(() => settingStore.get("Comfy.Sidebar.Location"));
	/**
	* Toggle Help Center and track UI button click.
	*/
	const toggleHelpCenter = () => {
		useTelemetry()?.trackUiButtonClicked({
			button_id: "sidebar_help_center_toggled",
			element_group: "sidebar"
		});
		helpCenterStore.toggle();
	};
	const closeHelpCenter = () => {
		helpCenterStore.hide();
	};
	/**
	* Handle What's New popup dismissal
	* Check if conflict modal should be shown after ComfyUI update
	*/
	const handleWhatsNewDismissed = async () => {
		try {
			if (await conflictDetection.shouldShowConflictModalAfterUpdate()) showConflictModal();
		} catch (error) {
			console.error("[HelpCenter] Error checking conflict modal:", error);
		}
	};
	/**
	* Show the node conflict dialog with current conflict data
	*/
	const showConflictModal = () => {
		showNodeConflictDialog({
			showAfterWhatsNew: true,
			dialogComponentProps: { onClose: () => {
				markConflictsAsSeen();
			} }
		});
	};
	onMounted(async () => {
		await releaseStore.initialize();
	});
	return {
		isHelpCenterVisible,
		shouldShowRedDot,
		sidebarLocation,
		toggleHelpCenter,
		closeHelpCenter,
		handleWhatsNewDismissed
	};
}
