//#region src/composables/useCanvasDrop.ts
var useCanvasDrop = (canvasRef) => {
	const modelToNodeStore = useModelToNodeStore();
	const litegraphService = useLitegraphService();
	const workflowService = useWorkflowService();
	usePragmaticDroppable(() => canvasRef.value, {
		getDropEffect: (args) => args.source.data.type === "tree-explorer-node" ? "copy" : "move",
		onDrop: async (event) => {
			const loc = event.location.current.input;
			const dndData = event.source.data;
			if (dndData.type === "tree-explorer-node") {
				const node = dndData.data;
				const basePos = useSharedCanvasPositionConversion().clientPosToCanvasPos([loc.clientX, loc.clientY]);
				if (node.data instanceof ComfyNodeDefImpl) {
					const nodeDef = node.data;
					const pos = [...basePos];
					pos[1] += LiteGraph.NODE_TITLE_HEIGHT;
					withNodeAddSource("sidebar_drag", () => litegraphService.addNodeOnGraph(nodeDef, { pos }));
				} else if (node.data instanceof ComfyModelDef) {
					const model = node.data;
					const pos = basePos;
					const nodeAtPos = app.canvas.graph?.getNodeOnPos(pos[0], pos[1]);
					let targetProvider = null;
					let targetGraphNode = null;
					if (nodeAtPos) {
						const providers = modelToNodeStore.getAllNodeProviders(model.directory);
						for (const provider of providers) if (provider.nodeDef.name === nodeAtPos.comfyClass) {
							targetGraphNode = nodeAtPos;
							targetProvider = provider;
						}
					}
					if (!targetGraphNode) {
						const provider = modelToNodeStore.getNodeProvider(model.directory);
						if (provider) {
							targetGraphNode = withNodeAddSource("sidebar_drag", () => litegraphService.addNodeOnGraph(provider.nodeDef, { pos }));
							targetProvider = provider;
						}
					}
					if (targetGraphNode) {
						const widget = targetGraphNode.widgets?.find((widget) => widget.name === targetProvider?.key);
						if (widget) widget.value = model.file_name;
					}
				} else if (node.data instanceof ComfyWorkflow) {
					const workflow = node.data;
					await workflowService.insertWorkflow(workflow, { position: basePos });
				}
			}
		}
	});
};
