//#region src/composables/useContextMenuTranslation.ts
/**
* Add translation for litegraph context menu.
*/
var useContextMenuTranslation = () => {
	legacyMenuCompat.install(LGraphCanvas.prototype, "getCanvasMenuOptions");
	const { getCanvasMenuOptions } = LGraphCanvas.prototype;
	const getCanvasCenterMenuOptions = function(...args) {
		const res = getCanvasMenuOptions.apply(this, args);
		const newApiItems = app.collectCanvasMenuItems(this);
		for (const item of newApiItems) res.push(item);
		const legacyItems = legacyMenuCompat.extractLegacyItems("getCanvasMenuOptions", this, ...args);
		for (const item of legacyItems) res.push(item);
		for (const item of res) if (item?.content) item.content = st(`contextMenu.${item.content}`, item.content);
		return res;
	};
	LGraphCanvas.prototype.getCanvasMenuOptions = getCanvasCenterMenuOptions;
	legacyMenuCompat.registerWrapper("getCanvasMenuOptions", getCanvasCenterMenuOptions, getCanvasMenuOptions, LGraphCanvas.prototype);
	legacyMenuCompat.install(LGraphCanvas.prototype, "getNodeMenuOptions");
	const nodeMenuFn = LGraphCanvas.prototype.getNodeMenuOptions;
	const getNodeMenuOptionsWithExtensions = function(...args) {
		const res = nodeMenuFn.apply(this, args);
		const node = args[0];
		const newApiItems = app.collectNodeMenuItems(node);
		for (const item of newApiItems) res.push(item);
		const legacyItems = legacyMenuCompat.extractLegacyItems("getNodeMenuOptions", this, ...args);
		for (const item of legacyItems) res.push(item);
		return res;
	};
	LGraphCanvas.prototype.getNodeMenuOptions = getNodeMenuOptionsWithExtensions;
	legacyMenuCompat.registerWrapper("getNodeMenuOptions", getNodeMenuOptionsWithExtensions, nodeMenuFn, LGraphCanvas.prototype);
	function translateMenus(values, options) {
		if (!values) return;
		const reInput = /Convert (.*) to input/;
		const reWidget = /Convert (.*) to widget/;
		const cvt = st("contextMenu.Convert ", "Convert ");
		const tinp = st("contextMenu. to input", " to input");
		const twgt = st("contextMenu. to widget", " to widget");
		for (const value of values) {
			if (typeof value === "string") continue;
			translateMenus(value?.submenu?.options, options);
			if (!value?.content) continue;
			if (te(`contextMenu.${value.content}`)) value.content = st(`contextMenu.${value.content}`, value.content);
			const extraInfo = options.extra || options.parentMenu?.options?.extra;
			const matchInput = value.content?.match(reInput);
			if (matchInput) {
				let match = matchInput[1];
				extraInfo?.inputs?.find((i) => {
					if (i.name != match) return false;
					match = i.label ? i.label : i.name;
				});
				extraInfo?.widgets?.find((i) => {
					if (i.name != match) return false;
					match = i.label ? i.label : i.name;
				});
				value.content = cvt + match + tinp;
				continue;
			}
			const matchWidget = value.content?.match(reWidget);
			if (matchWidget) {
				let match = matchWidget[1];
				extraInfo?.inputs?.find((i) => {
					if (i.name != match) return false;
					match = i.label ? i.label : i.name;
				});
				extraInfo?.widgets?.find((i) => {
					if (i.name != match) return false;
					match = i.label ? i.label : i.name;
				});
				value.content = cvt + match + twgt;
				continue;
			}
		}
	}
	const OriginalContextMenu = LiteGraph.ContextMenu;
	function ContextMenu(values, options) {
		if (options.title) options.title = st(`nodeDefs.${normalizeI18nKey(options.title)}.display_name`, options.title);
		translateMenus(values, options);
		return new OriginalContextMenu(values, options);
	}
	LiteGraph.ContextMenu = ContextMenu;
	LiteGraph.ContextMenu.prototype = OriginalContextMenu.prototype;
};
