//#region src/platform/workflow/persistence/composables/useWorkflowAutoSave.ts
function useWorkflowAutoSave() {
	const workflowStore = useWorkflowStore();
	const settingStore = useSettingStore();
	const workflowService = useWorkflowService();
	const autoSaveSetting = computed(() => settingStore.get("Comfy.Workflow.AutoSave"));
	const autoSaveDelay = computed(() => settingStore.get("Comfy.Workflow.AutoSaveDelay"));
	let autoSaveTimeout = null;
	let isSaving = false;
	let needsAutoSave = false;
	const scheduleAutoSave = () => {
		if (autoSaveTimeout) {
			clearTimeout(autoSaveTimeout);
			autoSaveTimeout = null;
		}
		if (autoSaveSetting.value === "after delay") {
			if (isSaving) {
				needsAutoSave = true;
				return;
			}
			const delay = autoSaveDelay.value;
			autoSaveTimeout = setTimeout(async () => {
				const activeWorkflow = workflowStore.activeWorkflow;
				if (activeWorkflow?.isModified && activeWorkflow.isPersisted) try {
					isSaving = true;
					await workflowService.saveWorkflow(activeWorkflow);
				} catch (err) {
					console.error("Auto save failed:", err);
				} finally {
					isSaving = false;
					if (needsAutoSave) {
						needsAutoSave = false;
						scheduleAutoSave();
					}
				}
			}, delay);
		}
	};
	watch(autoSaveSetting, (newSetting) => {
		if (autoSaveTimeout) {
			clearTimeout(autoSaveTimeout);
			autoSaveTimeout = null;
		}
		if (newSetting === "after delay" && workflowStore.activeWorkflow?.isModified) scheduleAutoSave();
	}, { immediate: true });
	const onGraphChanged = () => {
		scheduleAutoSave();
	};
	api.addEventListener("graphChanged", onGraphChanged);
	onUnmounted(() => {
		if (autoSaveTimeout) {
			clearTimeout(autoSaveTimeout);
			autoSaveTimeout = null;
		}
		api.removeEventListener("graphChanged", onGraphChanged);
	});
}
