//#region src/composables/useBrowserTabTitle.ts
var DEFAULT_TITLE = "ComfyUI";
var TITLE_SUFFIX = " - ComfyUI";
var useBrowserTabTitle = () => {
	const executionStore = useExecutionStore();
	const settingStore = useSettingStore();
	const workflowStore = useWorkflowStore();
	const workspaceStore = useWorkspaceStore();
	const executionText = computed(() => executionStore.isIdle ? "" : `[${Math.round(executionStore.executionProgress * 100)}%]`);
	const newMenuEnabled = computed(() => settingStore.get("Comfy.UseNewMenu") !== "Disabled");
	const isAutoSaveEnabled = computed(() => settingStore.get("Comfy.Workflow.AutoSave") === "after delay");
	const isActiveWorkflowModified = computed(() => !!workflowStore.activeWorkflow?.isModified);
	const isActiveWorkflowPersisted = computed(() => !!workflowStore.activeWorkflow?.isPersisted);
	const shouldShowUnsavedIndicator = computed(() => {
		if (workspaceStore.shiftDown) return false;
		if (isAutoSaveEnabled.value) return false;
		if (!isActiveWorkflowPersisted.value) return true;
		if (isActiveWorkflowModified.value) return true;
		return false;
	});
	const isUnsavedText = computed(() => shouldShowUnsavedIndicator.value ? " *" : "");
	const workflowNameText = computed(() => {
		const workflowName = workflowStore.activeWorkflow?.filename;
		return workflowName ? isUnsavedText.value + workflowName + TITLE_SUFFIX : DEFAULT_TITLE;
	});
	const nodeExecutionTitle = computed(() => {
		const runningNodes = Object.entries(executionStore.nodeProgressStates).filter(([_, state]) => state.state === "running");
		if (runningNodes.length === 0) return "";
		if (runningNodes.length > 1) return `${executionText.value}[${runningNodes.length} ${t("g.nodesRunning", "nodes running")}]`;
		const [, state] = runningNodes[0];
		const progress = Math.round(state.value / state.max * 100);
		const nodeLabel = executionStore.executingNode?.type?.trim() || executionStore.executingNode?.title?.trim() || "Node";
		return `${executionText.value}[${progress}%] ${nodeLabel}`;
	});
	const workflowTitle = computed(() => executionText.value + (newMenuEnabled.value ? workflowNameText.value : DEFAULT_TITLE));
	useTitle(computed(() => nodeExecutionTitle.value || workflowTitle.value));
};
