//#region src/platform/remote/comfyui/useQueuePolling.ts
var BASE_INTERVAL_MS = 8e3;
var MAX_INTERVAL_MS = 32e3;
var BACKOFF_MULTIPLIER = 1.5;
function useQueuePolling() {
	const queueStore = useQueueStore();
	const delay = ref(BASE_INTERVAL_MS);
	const { start, stop } = useTimeoutFn(() => {
		if (queueStore.activeJobsCount !== 1 || queueStore.isLoading) return;
		delay.value = Math.min(delay.value * BACKOFF_MULTIPLIER, MAX_INTERVAL_MS);
		queueStore.update();
	}, delay, { immediate: false });
	function scheduleNextPoll() {
		if (queueStore.activeJobsCount === 1 && !queueStore.isLoading) start();
		else stop();
	}
	watch(() => queueStore.activeJobsCount, () => {
		delay.value = BASE_INTERVAL_MS;
		scheduleNextPoll();
	}, { immediate: true });
	watch(() => queueStore.isLoading, (loading, wasLoading) => {
		if (wasLoading && !loading) scheduleNextPoll();
	}, { flush: "sync" });
}
//#endregion
//#region src/composables/useReconnectQueueRefresh.ts
/**
* After a WebSocket reconnect, refresh the queue from the server and clear
* any active job that finished during the disconnect window. Returns the
* handler so the caller can wire it to the `reconnected` api event.
*
* `update()` preserves the previous queue snapshot when the fetch fails, so
* if the network is still flaky we reconcile against the last known good
* state rather than an empty (and falsely "stale") set.
*/
function useReconnectQueueRefresh() {
	const queueStore = useQueueStore();
	const executionStore = useExecutionStore();
	return async function refreshOnReconnect() {
		await queueStore.update();
		const activeJobIds = new Set([...queueStore.runningTasks.map((t) => t.jobId), ...queueStore.pendingTasks.map((t) => t.jobId)]);
		executionStore.clearActiveJobIfStale(activeJobIds);
	};
}
//#endregion
//#region src/composables/useReconnectingNotification.ts
var RECONNECT_TOAST_DELAY_MS = 1500;
function useReconnectingNotification() {
	const { t } = useI18n();
	const toast = useToast();
	const settingStore = useSettingStore();
	const reconnectingMessage = {
		severity: "error",
		summary: t("g.reconnecting")
	};
	const reconnectingToastShown = ref(false);
	const { start, stop } = useTimeoutFn(() => {
		toast.add(reconnectingMessage);
		reconnectingToastShown.value = true;
	}, RECONNECT_TOAST_DELAY_MS, { immediate: false });
	function onReconnecting() {
		if (settingStore.get("Comfy.Toast.DisableReconnectingToast")) return;
		start();
	}
	function onReconnected() {
		stop();
		if (reconnectingToastShown.value) {
			toast.remove(reconnectingMessage);
			toast.add({
				severity: "success",
				summary: t("g.reconnected"),
				life: 2e3
			});
			reconnectingToastShown.value = false;
		}
	}
	return {
		onReconnecting,
		onReconnected
	};
}
//#endregion
//#region src/composables/useProgressFavicon.ts
var useProgressFavicon = () => {
	const defaultFavicon = "/assets/images/favicon_progress_16x16/frame_9.png";
	const favicon = useFavicon(defaultFavicon);
	const executionStore = useExecutionStore();
	const totalFrames = 10;
	watch([() => executionStore.executionProgress, () => executionStore.isIdle], ([progress, isIdle]) => {
		if (isIdle) favicon.value = defaultFavicon;
		else favicon.value = `/assets/images/favicon_progress_16x16/frame_${Math.min(Math.max(0, Math.floor(progress * totalFrames)), totalFrames - 1)}.png`;
	});
};
