//#region src/services/autoQueueService.ts
function setupAutoQueueHandler() {
	const queueCountStore = useQueuePendingTaskCountStore();
	const queueSettingsStore = useQueueSettingsStore();
	let graphHasChanged = false;
	let internalCount = 0;
	api.addEventListener("graphChanged", () => {
		if (queueSettingsStore.mode === "change") if (internalCount) graphHasChanged = true;
		else {
			graphHasChanged = false;
			app.queuePrompt(0, queueSettingsStore.batchCount);
			internalCount++;
		}
	});
	queueCountStore.$subscribe(async () => {
		internalCount = queueCountStore.count;
		if (!internalCount && !app.lastExecutionError) {
			if (isInstantRunningMode(queueSettingsStore.mode) || queueSettingsStore.mode === "change" && graphHasChanged) {
				graphHasChanged = false;
				await app.queuePrompt(0, queueSettingsStore.batchCount);
			}
		}
	}, { detached: true });
}
